void ZopfliDeflate(const ZopfliOptions *options, int btype, int final,
                   const unsigned char *in, size_t insize,
                   unsigned char *bp, unsigned char **out, size_t *outsize)
// clang-format off
/* ZopfliDeflate chops the input into master blocks of ZOPFLI_MASTER_BLOCK_SIZE
   bytes and feeds each to ZopfliDeflatePart.  We pin the same sound regime as
   that callee: btype==0 (the only self-consistent path -- see ZopfliDeflatePart)
   and a single master block (insize <= ZOPFLI_MASTER_BLOCK_SIZE) so the do/while
   makes exactly one call.  A second iteration is impossible to prove anyway:
   ZopfliDeflatePart's contract ensures *bp==0, but its precondition demands
   *bp in 1..7, so any path that calls it twice is dead.  The requires below
   forward ZopfliDeflatePart's own precondition for that single call; inend is
   bounded only above by the master-block size, which lets the masterfinal and
   size/index arithmetic mutants be killed when they push the forwarded inend
   (is_fresh(in, inend)) past the actual insize bytes. */
__CPROVER_requires(btype == 0)
__CPROVER_requires(final == 0 || final == 1)
__CPROVER_requires(insize >= 1 && insize <= ZOPFLI_MASTER_BLOCK_SIZE)
__CPROVER_requires(__CPROVER_is_fresh(options, sizeof(*options)))
__CPROVER_requires(__CPROVER_is_fresh(in, insize))
__CPROVER_requires(__CPROVER_is_fresh(bp, sizeof(*bp)) && *bp >= 1 && *bp <= 7)
__CPROVER_requires(__CPROVER_is_fresh(outsize, sizeof(*outsize)) && *outsize == 1)
__CPROVER_requires(__CPROVER_is_fresh(out, sizeof(*out)) &&
                   __CPROVER_is_fresh(*out, *outsize))
__CPROVER_assigns(*bp, *outsize, *out, (*out)[*outsize - 1])
__CPROVER_ensures(*bp == 0)
// clang-format on
{
    size_t offset = *outsize;
    size_t i = 0;
    do
    {
        int masterfinal = (i + ZOPFLI_MASTER_BLOCK_SIZE >= insize);
        int final2 = final && masterfinal;
        size_t size = masterfinal ? insize - i : ZOPFLI_MASTER_BLOCK_SIZE;
        ZopfliDeflatePart(options, btype, final2,
                          in, i, i + size, bp, out, outsize);
        i += size;
    } while (i < insize);
    if (options->verbose)
    {
        fprintf(stderr,
                "Original Size: %lu, Deflate: %lu, Compression: %.2f%%\n",
                (unsigned long)insize, (unsigned long)(*outsize - offset),
                100.0 * (double)(insize - (*outsize - offset)) / (double)insize);
    }
}

void single_test(const unsigned char *in, int btype, int blocksplitting, int blocksplittingmax)
{
    ZopfliOptions options;

    // Configure options
    options.verbose = 1;
    options.verbose_more = 0; // Reduce internal verbose output
    options.numiterations = 15;
    options.blocksplitting = blocksplitting;
    options.blocksplittinglast = 0;
    options.blocksplittingmax = blocksplittingmax;

